    .map((entry) => {
      const item = {
        agent_run_id: entry.record.id,
        path: entry.path,
        status: entry.record.status,
        agent_role: entry.record.agent_role,
        blocking_issues: entry.record.blocking_issues ?? [],
        next_actions: entry.record.next_actions ?? []
      };

      if (entry.record.mode) {
